type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';

type Point = { x: number; y: number };

class AppComponent {
  snake: Point[] = INITIAL_SNAKE.map((point) => ({ ...point }));
  direction: Direction = 'RIGHT';
  pendingDirection: Direction = 'RIGHT';
  food: Point = { ...INITIAL_FOOD };
  isRunning = false;
  isGameOver = false;
  score = 0;
  private timerId: ReturnType<typeof setInterval> | null = null;

  onKeydown(event: KeyboardEvent): void {
    const nextDirection = this.directionFromKey(event.key.toLowerCase());
    if (!nextDirection) return;

    const activeDirection = this.pendingDirection || this.direction;
    if (OPPOSITE[activeDirection] === nextDirection) return;
    this.pendingDirection = nextDirection;
  }

  start(): void {
    if (this.isRunning || this.isGameOver) return;
    this.isRunning = true;
    this.clearTimer();
    this.timerId = setInterval(() => this.tick(), STEP_MS);
  }

  reset(): void {
    this.clearTimer();
    this.snake = INITIAL_SNAKE.map((point) => ({ ...point }));
    this.direction = 'RIGHT';
    this.pendingDirection = 'RIGHT';
    this.food = { ...INITIAL_FOOD };
    this.isRunning = false;
    this.isGameOver = false;
    this.score = 0;
  }

  private tick(): void {
    if (!this.isRunning || this.isGameOver) return;

    const stepDirection = this.pendingDirection || this.direction;
    const nextHead = this.moveHead(this.snake[0], stepDirection);

    if (this.outOfBounds(nextHead)) {
      this.isGameOver = true;
      this.pause();
      return;
    }

    const bodyToCheck = this.snake.slice(0, -1);
    if (bodyToCheck.some((part) => part.x === nextHead.x && part.y === nextHead.y)) {
      this.isGameOver = true;
      this.pause();
      return;
    }

    const ateFood = nextHead.x === this.food.x && nextHead.y === this.food.y;
    const nextSnake = [nextHead, ...this.snake];
    if (!ateFood) nextSnake.pop();
    else {
      this.score += 1;
      this.food = this.randomFood(nextSnake);
    }

    this.snake = nextSnake;
    this.direction = stepDirection;
  }

  private randomFood(snake: Point[]): Point {
    const occupied = new Set(snake.map((point) => `${point.x},${point.y}`));
    const free = this.allCells().filter((cell) => !occupied.has(`${cell.x},${cell.y}`));
    return free[Math.floor(Math.random() * free.length)] ?? { x: 0, y: 0 };
  }

  ngOnDestroy(): void {
    this.clearTimer();
  }
}
